import type {
  AttemptListItem,
  AttemptSummary,
  ChatMessage,
  DocumentDetail,
  DocumentSummary,
  Plan,
  QuizDTO
} from './types'

const BASE = 'http://localhost:3003'

export class ApiError extends Error {
  status: number
  constructor(message: string, status: number) {
    super(message)
    this.status = status
  }
}

async function jsonFetch<T>(path: string, init?: RequestInit): Promise<T> {
  const headers: Record<string, string> = {}
  if (init?.method == 'POST' && init?.body != null) {
    headers['Content-Type'] = 'application/json'
  }
  const res = await fetch(`${BASE}${path}`, { ...init, headers, body: init?.body })
  if (!res.ok) {
    let msg = `Request failed (${res.status})`
    const body = await res.json()
    msg = body.error ?? msg
    throw new ApiError(msg, res.status)
  }
  if (res.status === 204) return undefined as unknown as T
  return (await res.json()) as T
}

export async function listDocuments(): Promise<DocumentSummary[]> {
  return jsonFetch<DocumentSummary[]>('/api/documents')
}

export async function getDocument(id: number): Promise<DocumentDetail> {
  return jsonFetch<DocumentDetail>(`/api/documents/${id}`)
}

export async function uploadPdf(file: File): Promise<DocumentDetail> {
  const form = new FormData()
  form.append('file', file)
  const res = await fetch(`${BASE}/api/documents/upload`, { method: 'POST', body: form })
  if (!res.ok) {
    let msg = 'Upload failed'
    const body = await res.json()
    msg = body.error ?? msg
    throw new ApiError(msg, res.status)
  }
  return (await res.json()) as DocumentDetail
}

export async function listPlansForDocument(id: number): Promise<Plan[]> {
  return jsonFetch<Plan[]>(`/api/documents/${id}/plans`)
}

export async function createPlan(documentId: number): Promise<Plan> {
  return jsonFetch<Plan>(`/api/documents/${documentId}/plans`, { method: 'POST' })
}

export async function getPlan(planId: number): Promise<Plan> {
  return jsonFetch<Plan>(`/api/lesson-plans/${planId}`)
}

export async function approvePlan(planId: number): Promise<Plan> {
  return jsonFetch<Plan>(`/api/lesson-plans/${planId}/approve`, { method: 'POST' })
}

export async function listQuizzes(planId: number): Promise<QuizDTO[]> {
  return jsonFetch<QuizDTO[]>(`/api/lesson-plans/${planId}/quizzes`)
}

export async function generateQuiz(planId: number, objectiveIndex: number): Promise<QuizDTO> {
  return jsonFetch<QuizDTO>(`/api/lesson-plans/${planId}/quizzes`, {
    method: 'POST',
    body: JSON.stringify({ objectiveIndex })
  })
}

interface Explanation {
  explanation: string
  correctIndex: number
}

export async function getExplanation(quizId: number): Promise<Explanation> {
  return jsonFetch(`/api/quizzes/${quizId}/explain`, { method: 'POST', body: '{}' })
}

interface AnswerData {
  correct: boolean
}

export async function checkAnswer(quizId: number, learnerIndex: number): Promise<AnswerData> {
  return jsonFetch(`/api/quizzes/${quizId}/check`, {
    method: 'POST',
    body: JSON.stringify({ learnerIndex })
  })
}

export async function getHint(quizId: number, previousGuessIndex: number | null): Promise<{ hint: string }> {
  return jsonFetch(`/api/quizzes/${quizId}/hint`, {
    method: 'POST',
    body: JSON.stringify({ previousGuessIndex })
  })
}

interface Message {
  message: string
}

export async function learnMore(quizId: number, learnerQuestion: string, history: ChatMessage[]): Promise<Message> {
  return jsonFetch(`/api/quizzes/${quizId}/ai-help`, {
    method: 'POST',
    body: JSON.stringify({ learnerQuestion, history })
  })
}

interface Attempts {
  quizId: number
  learnerIndex: number | null
  attempts: number
}

export async function completeAttempt(planId: number, answers: Array<Attempts>): Promise<AttemptSummary> {
  return jsonFetch(`/api/lesson-plans/${planId}/complete`, {
    method: 'POST',
    body: JSON.stringify({ answers })
  })
}

export async function listAttempts(planId: number): Promise<AttemptListItem[]> {
  return jsonFetch<AttemptListItem[]>(`/api/lesson-plans/${planId}/attempts`)
}

export async function getAttempt(attemptId: number): Promise<AttemptSummary> {
  return jsonFetch<AttemptSummary>(`/api/attempts/${attemptId}`)
}

import { useNavigate } from 'react-router-dom'
import { Clock, FileText, Loader2, AlertTriangle, RefreshCw, ChevronRight, Layers } from 'lucide-react'
import { cn } from '#lib/utils'
import { Badge } from '#components/ui/badge'
import { Button } from '#components/ui/button'
import type { DocumentSummary } from '#lib/types'
import { difficultyLabel, formatDate } from '#lib/format'

interface Props {
  doc: DocumentSummary
  onStartLearning?: (documentId: number) => void
}

export function DocumentCard({ doc, onStartLearning }: Props) {
  const navigate = useNavigate()
  const ready = doc.status === 'ready'
  const processing = doc.status === 'processing'
  const failed = doc.status === 'failed'

  const start = () => {
    if (doc.plan) {
      navigate(`/learn/${doc.plan.id}`)
    } else if (onStartLearning) {
      onStartLearning(doc.id)
    }
  }

  const title = doc.title || doc.filename.replace(/\.pdf$/i, '')

  return (
    <div className="group flex flex-col rounded-2xl border border-border bg-card p-5 shadow-sm transition-all hover:shadow-md hover:border-primary/40">
      <div className="flex items-start gap-3">
        <div
          className={cn(
            'flex size-11 shrink-0 items-center justify-center rounded-xl',
            ready
              ? 'bg-primary/10 text-primary'
              : processing
                ? 'bg-accent text-accent-foreground'
                : 'bg-danger/10 text-danger'
          )}
        >
          {processing ? (
            <Loader2 className="size-5 animate-spin" />
          ) : failed ? (
            <AlertTriangle className="size-5" />
          ) : (
            <FileText className="size-5" />
          )}
        </div>
        <div className="min-w-0 flex-1">
          <p className="truncate text-sm font-semibold" title={title}>
            {title}
          </p>
          <p className="truncate text-xs text-muted-foreground" title={doc.filename}>
            {doc.filename}
          </p>
        </div>
        {doc.plan && <Badge variant="secondary">{difficultyLabel(doc.plan.difficulty)}</Badge>}
      </div>

      <div className="mt-4 flex flex-wrap items-center gap-x-4 gap-y-1 text-xs text-muted-foreground">
        <span className="inline-flex items-center gap-1">
          <Clock className="size-3.5" />
          {formatDate(doc.created_at)}
        </span>
        {ready && (
          <span className="inline-flex items-center gap-1">
            <FileText className="size-3.5" />
            {doc.markdown_chars.toLocaleString()} chars
          </span>
        )}
        {doc.attemptCount > 0 && (
          <span className="inline-flex items-center gap-1">
            <Layers className="size-3.5" />
            {doc.attemptCount} attempt{doc.attemptCount > 1 ? 's' : ''}
          </span>
        )}
      </div>

      {failed && (
        <p className="mt-3 line-clamp-2 rounded-md bg-danger/10 px-2.5 py-1.5 text-xs text-danger">
          {doc.error ?? 'Failed to process PDF'}
        </p>
      )}

      <div className="mt-4 flex items-center gap-2">
        {ready && !doc.plan && (
          <Button size="sm" className="gap-1.5" onClick={start}>
            Start learning
            <ChevronRight className="size-3.5" />
          </Button>
        )}
        {ready && doc.plan && (
          <>
            <Button size="sm" className="gap-1.5" onClick={start}>
              {doc.attemptCount > 0 ? (
                <>
                  <RefreshCw className="size-3.5" />
                  Retake
                </>
              ) : (
                <>
                  Continue
                  <ChevronRight className="size-3.5" />
                </>
              )}
            </Button>
            {doc.attemptCount > 0 && (
              <Button size="sm" variant="ghost" className="gap-1.5" onClick={start}>
                Review plan
              </Button>
            )}
          </>
        )}
        {processing && (
          <Button size="sm" variant="outline" disabled className="gap-1.5">
            <Loader2 className="size-3.5 animate-spin" />
            Parsing...
          </Button>
        )}
      </div>
    </div>
  )
}

